from dataclasses import dataclass, field
from typing import Dict


@dataclass
class ComputeBudget:
    art_name: str
    total_gpu_hours: float
    total_api_tokens_M: float    # millions of tokens

    team_gpu_alloc: Dict[str, float] = field(default_factory=dict)
    team_token_alloc: Dict[str, float] = field(default_factory=dict)

    # Alert thresholds (percentage of budget consumed)
    amber_threshold_pct: float = 70.0
    red_threshold_pct: float = 90.0

    def add_team_allocation(
        self, team: str, gpu_hours: float, tokens_M: float
    ) -> None:
        self.team_gpu_alloc[team] = gpu_hours
        self.team_token_alloc[team] = tokens_M

    def committed_gpu(self) -> float:
        return sum(self.team_gpu_alloc.values())

    def unallocated_gpu(self) -> float:
        return self.total_gpu_hours - self.committed_gpu()

    def validate(self) -> list[str]:
        issues = []
        if self.committed_gpu() > self.total_gpu_hours:
            over = self.committed_gpu() - self.total_gpu_hours
            issues.append(f"GPU overcommit by {over:.1f} h — reduce team allocations")
        if self.unallocated_gpu() / self.total_gpu_hours < 0.10:
            issues.append("Reserve buffer < 10% — risky for unplanned experiments")
        return issues


# PI Planning closing session example
budget = ComputeBudget(
    art_name="AI Products ART",
    total_gpu_hours=2000.0,
    total_api_tokens_M=500.0,
)
budget.add_team_allocation("Summarisation Team", gpu_hours=600.0, tokens_M=150.0)
budget.add_team_allocation("Chat UI Team",        gpu_hours=100.0, tokens_M=200.0)
budget.add_team_allocation("LLM Gateway Team",    gpu_hours=400.0, tokens_M=80.0)
# 900 h committed, 1 100 h buffer (55 %) — healthy

issues = budget.validate()
if issues:
    for issue in issues:
        print(f"  ⚠ {issue}")
else:
    print(f"Budget validated: {budget.committed_gpu():.0f}/{budget.total_gpu_hours:.0f} GPU-h allocated, {budget.unallocated_gpu():.0f} h in reserve")

from dataclasses import dataclass, field
from statistics import mean


@dataclass
class ConfidenceVoteResult:
    objective_id: str
    team: str
    scores: list[int]            # each team member scores 1–5
    uncertainty_reason: str = "" # free-text if mean < 3

    def mean_score(self) -> float:
        return mean(self.scores) if self.scores else 0.0

    def outcome(self) -> str:
        m = self.mean_score()
        if m >= 4.0:
            return "COMMIT"
        elif m >= 3.0:
            return "COMMIT_WITH_RISK"  # logged on ROAM board
        else:
            return "RENEGOTIATE"       # objective must change before close of PI Planning


def run_confidence_vote(
    objective_id: str,
    team: str,
    member_scores: list[int],
) -> ConfidenceVoteResult:
    result = ConfidenceVoteResult(
        objective_id=objective_id,
        team=team,
        scores=member_scores,
    )
    print(
        f"Objective {objective_id} — mean={result.mean_score():.1f} → {result.outcome()}"
    )
    return result


# Example: summarisation team votes on their two objectives
votes = [
    run_confidence_vote("OBJ-1", "Summarisation Team", [4, 5, 4, 3, 4]),  # mean 4.0
    run_confidence_vote("OBJ-2", "Summarisation Team", [2, 3, 2, 1, 2]),  # mean 2.0 → renegotiate
]

renegotiate = [v for v in votes if v.outcome() == "RENEGOTIATE"]
if renegotiate:
    print(f"\n{len(renegotiate)} objective(s) require scope renegotiation before PI close")
